CREATE VIEW "public"."courseEventView" AS (select "courseEvent"."id", "courseEvent"."courseId", "courseEvent"."locationType", "courseEvent"."virtualLink", "courseEvent"."physicalAddress", "courseEvent"."seats", "courseEvent"."classStartDatetime", "courseEvent"."instructorId", "course"."courseName", "course"."description", "course"."creditHours", "course"."priceCents" from "courseEvent" inner join "course" on "courseEvent"."courseId" = "course"."id");--> statement-breakpoint
CREATE VIEW "public"."reservationView" AS (select "reservation"."profileId", "reservation"."courseEventId", "reservation"."creditHours", "reservation"."paymentStatus", "profile"."firstName", "profile"."lastName", "profile"."isMember", "courseEvent"."classStartDatetime", "course"."id", "course"."courseName", "course"."creditHours" as "courseCreditHours" from "reservation" inner join "profile" on "reservation"."profileId" = "profile"."id" inner join "courseEvent" on "reservation"."courseEventId" = "courseEvent"."id" inner join "course" on "course"."id" = "courseEvent"."courseId");